// import React, { useState } from "react";

const categoryColors = {
  Languages: "var(--accent)",
  Frameworks: "var(--accent2)",
  Tools: "var(--accent3)",
  Databases: "#34d399",
  Concepts: "#f472b6",
};

export function SectionLabel({ text }) {
  return (
    <div className="section-label">
      <span className="line" />
      <span className="label-text">{text}</span>
    </div>
  );
}

export const sectionTitle = {
  fontFamily: "var(--font-display)",
  fontWeight: 800,
  fontSize: "clamp(1.6rem, 3.5vw, 2.5rem)",
  letterSpacing: "-0.02em",
  marginBottom: "1.75rem",
  lineHeight: 1.1,
};

export default function Skills({ skills }) {
  const [active, setActive] = useState("Languages");
  const categories = Object.keys(skills);

  return (
    <>
      <style>{`
        .skills-section {
          padding: clamp(2.5rem, 6vw, 5rem) clamp(1rem, 5vw, 4rem);
          max-width: 1200px;
          margin: auto;
        }

        /* Section Label */
        .section-label {
          display: inline-flex;
          align-items: center;
          gap: 8px;
          margin-bottom: 0.75rem;
        }
        .section-label .line {
          width: 22px;
          height: 1px;
          background: var(--accent);
        }
        .label-text {
          font-size: 0.7rem;
          color: var(--accent);
          font-family: var(--font-display);
          font-weight: 700;
          letter-spacing: 0.12em;
          text-transform: uppercase;
        }

        /* Tabs */
        .skill-tabs {
          display: flex;
          flex-wrap: wrap;
          gap: 0.6rem;
          margin-bottom: 2rem;
        }

        .skill-tab {
          padding: 8px 16px;
          border-radius: 999px;
          border: 1px solid var(--border);
          font-family: var(--font-display);
          font-weight: 600;
          font-size: clamp(0.7rem, 1vw, 0.9rem);
          cursor: pointer;
          transition: all 0.25s ease;
          white-space: nowrap;
        }

        .skill-tab:hover {
          transform: translateY(-2px);
        }

        /* Skills Grid */
        .skill-chips {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(130px, 1fr));
          gap: 0.8rem;
        }

        .skill-chip {
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 6px;
          text-align: center;
          background: var(--surface2);
          border-radius: 8px;
          padding: 10px 12px;
          font-weight: 500;
          font-size: clamp(0.78rem, 1vw, 0.95rem);
          color: var(--text);
          border: 1px solid transparent;
          transition: all 0.25s ease;
          cursor: default;
        }

        .skill-chip:hover {
          transform: translateY(-3px) scale(1.02);
        }

        /* Tablet */
        @media (max-width: 768px) {
          .skill-chips {
            grid-template-columns: repeat(auto-fit, minmax(110px, 1fr));
          }
        }

        /* Mobile */
        @media (max-width: 480px) {
          .skill-tabs {
            justify-content: center;
          }

          .skill-chips {
            grid-template-columns: repeat(2, 1fr);
            gap: 0.6rem;
          }

          .skill-chip {
            font-size: 0.8rem;
            padding: 8px;
          }
        }
      `}</style>

      <section className="skills-section" id="skills">
        <SectionLabel text="Expertise" />
        <h2 style={sectionTitle}>Technical Skills</h2>

        <div className="skill-tabs">
          {categories.map((cat) => (
            <button
              key={cat}
              className="skill-tab"
              onClick={() => setActive(cat)}
              style={{
                borderColor:
                  active === cat ? categoryColors[cat] : "var(--border)",
                background:
                  active === cat
                    ? `${categoryColors[cat]}18`
                    : "transparent",
                color:
                  active === cat
                    ? categoryColors[cat]
                    : "var(--muted)",
              }}
            >
              {cat}
            </button>
          ))}
        </div>

        <div className="skill-chips">
          {skills[active].map((skill, i) => (
            <div
              key={i}
              className="skill-chip"
              style={{
                borderColor: `${categoryColors[active]}30`,
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.borderColor = categoryColors[active];
                e.currentTarget.style.background = `${categoryColors[active]}10`;
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.borderColor = `${categoryColors[active]}30`;
                e.currentTarget.style.background = "var(--surface2)";
              }}
            >
              <span style={{ color: categoryColors[active] }}>▸</span>
              {skill}
            </div>
          ))}
        </div>
      </section>
    </>
  );
}
